import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, HealingResult, ProjectContext } from "../../base.ts";

/**
 * 🧪 Dr. Testify — PhD in TypeScript Test Integrity & Coverage
 * Generated by Sovereign Forge.
 */
export class TestifyPersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "testify";
        this.name = "Testify";
        this.emoji = "🧪";
        this.role = "PhD Quality & Testing Engineer";
        this.phd_identity = "TypeScript Test Integrity & Coverage";
        this.stack = "Bun";
        this.healingPrompt = "Fix the following testing or quality assurance issue. Eliminate flaky tests, improve assertion specificity, and increase coverage. Return ONLY the corrected code or a specific diff.";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        if (this.healingPrompt) {
            const { findings } = await this.auditAndHeal();
            return findings;
        }
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: [".ts",".js"],
            rules: [
          {
                    "regex": "describe\\s*\\([^)]*\\)\\s*\\{[^}]*describe",
                    "issue": "Complexidade: Testes muito aninhados — divida em arquivos menores PhD.",
                    "severity": "low"
          },
          {
                    "regex": "it\\s*\\([^)]*\\)\\s*\\{\\s*\\}",
                    "issue": "Vazio: Teste sem implementação (placeholder) PhD.",
                    "severity": "high"
          },
          {
                    "regex": "expect\\([^)]*\\)\\.toBeDefined\\(\\)",
                    "issue": "Fraco: toBeDefined() é uma asserção fraca — use valores específicos PhD.",
                    "severity": "medium"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Testify operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Testify, PhD em TypeScript Test Integrity & Coverage. Sua missão é garantir a excelência via governança PhD.`;
    }
}
